script:
(function (root_element) {
  const root = root_element.querySelector("#fbr_fiscal_year_kpi_block");
  if (!root) return;
  const $ = (selector) => root.querySelector(selector);
  const chartCanvas = $("#fbr_kpi_sales_purchase_chart");

  function money(value, currency) {
    const amount = Math.round(Number(value || 0));
    if (typeof format_currency === "function") {
      return format_currency(amount, currency || "PKR", 0).replace(/([.,])00\b/g, "");
    }
    return "Rs " + amount.toLocaleString();
  }

  function num(value) {
    return Math.round(Number(value || 0)).toLocaleString();
  }

  function setText(selector, value) {
    const element = $(selector);
    if (element) element.textContent = value;
  }

  function setChange(selector, value) {
    const element = $(selector);
    if (!element) return;
    const numeric = Number(value || 0);
    element.textContent = `${numeric >= 0 ? "+" : ""}${numeric.toFixed(1)}%`;
    element.classList.toggle("bad", numeric < 0);
  }

  function drawBarChart(canvas, labels, sales, purchases) {
    if (!canvas) return;
    const dpr = window.devicePixelRatio || 1;
    const rect = canvas.parentElement.getBoundingClientRect();
    const width = Math.max(640, rect.width || 900);
    const height = Math.max(260, rect.height || 285);
    canvas.width = width * dpr;
    canvas.height = height * dpr;
    canvas.style.width = width + "px";
    canvas.style.height = height + "px";
    const ctx = canvas.getContext("2d");
    ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
    ctx.clearRect(0, 0, width, height);

    const allValues = [...sales, ...purchases].map((v) => Math.abs(Number(v || 0)));
    const maxValue = Math.max(...allValues, 1);
    const chart = { left: 50, right: 20, top: 22, bottom: 38 };
    const chartWidth = width - chart.left - chart.right;
    const chartHeight = height - chart.top - chart.bottom;
    const groupWidth = chartWidth / Math.max(labels.length, 1);
    const barWidth = Math.max(16, Math.min(54, groupWidth * 0.32));

    ctx.font = "10px Segoe UI, sans-serif";
    ctx.strokeStyle = "#eef2f7";
    ctx.fillStyle = "#334155";
    ctx.lineWidth = 1;
    for (let i = 0; i <= 4; i++) {
      const y = chart.top + (chartHeight / 4) * i;
      ctx.beginPath();
      ctx.moveTo(chart.left, y);
      ctx.lineTo(width - chart.right, y);
      ctx.stroke();
      const tick = Math.round(maxValue - (maxValue / 4) * i);
      ctx.fillText(tick.toLocaleString(), 0, y + 3);
    }

    function bar(x, value, color) {
      const h = (Math.abs(Number(value || 0)) / maxValue) * chartHeight;
      const y = chart.top + chartHeight - h;
      ctx.fillStyle = color;
      ctx.fillRect(x, y, barWidth, h);
      ctx.save();
      ctx.translate(x + barWidth / 2, Math.max(chart.top + 18, y + 8));
      ctx.rotate(-Math.PI / 2);
      ctx.fillStyle = "#0f172a";
      ctx.strokeStyle = "#fff";
      ctx.lineWidth = 3;
      ctx.font = "700 10px Segoe UI, sans-serif";
      const label = Math.round(Number(value || 0)).toLocaleString();
      ctx.strokeText(label, 0, 3);
      ctx.fillText(label, 0, 3);
      ctx.restore();
    }

    labels.forEach((label, index) => {
      const center = chart.left + groupWidth * index + groupWidth / 2;
      bar(center - barWidth - 2, sales[index] || 0, "#2da9e1");
      bar(center + 2, purchases[index] || 0, "#47c878");
      ctx.fillStyle = "#334155";
      ctx.font = "10px Segoe UI, sans-serif";
      ctx.textAlign = "center";
      ctx.fillText(label, center, height - 12);
    });
    ctx.textAlign = "left";
  }

  function render(data) {
    const currency = data.currency || "PKR";
    const summary = data.summary || {};
    const sales = data.sales || {};
    const purchases = data.purchases || {};
    setText("#fbr_kpi_period", `${data.company || ""} · ${data.period_label || "Last fiscal year"}`);
    setText("#fbr_kpi_revenue", money(summary.revenue, currency));
    setText("#fbr_kpi_expenses", money(summary.expenses, currency));
    setText("#fbr_kpi_profit", money(summary.profit, currency));
    setText("#fbr_kpi_margin", `${Number(summary.margin || 0).toFixed(1)}%`);
    setText("#fbr_kpi_sales_inclusive", money(sales.inclusive, currency));
    setText("#fbr_kpi_sales_tax", money(sales.tax, currency));
    setText("#fbr_kpi_sales_exclusive", money(sales.exclusive, currency));
    setText("#fbr_kpi_sales_count", num(sales.invoice_count));
    setText("#fbr_kpi_submitted", num(sales.submitted_count));
    setText("#fbr_kpi_draft", num(sales.draft_count));
    setText("#fbr_kpi_fbr_success", num(sales.fbr_success_count));
    setText("#fbr_kpi_fbr_success_line", num(sales.fbr_success_count));
    setText("#fbr_kpi_fbr_pending", num(sales.fbr_pending_count));
    setText("#fbr_kpi_purchase_activity", `${num(purchases.purchase_count)} · ${money(purchases.purchase_total, currency)}`);
    setChange("#fbr_kpi_revenue_change", summary.revenue_change);
    setChange("#fbr_kpi_expenses_change", summary.expenses_change);
    setChange("#fbr_kpi_profit_change", summary.profit_change);
    setChange("#fbr_kpi_margin_change", summary.margin_change);
    const trend = data.trend || {};
    drawBarChart(chartCanvas, trend.labels || [], trend.sales || [], trend.purchases || []);
  }

  frappe.call({
    method: "fbr_integration.custom_dashboard_api.fiscal_year_kpi_block_data",
    callback: function (r) {
      render(r.message || {});
    },
    error: function () {
      root.innerHTML = '<div class="fbr-kpi-empty">Unable to load fiscal year summary.</div>';
    },
  });

  window.addEventListener("resize", frappe.utils.debounce(function () {
    frappe.call({
      method: "fbr_integration.custom_dashboard_api.fiscal_year_kpi_block_data",
      callback: function (r) { render(r.message || {}); },
    });
  }, 300));
})(root_element);
